import { useEffect } from "react";
import { useNavigate } from "react-router-dom";

export default function FacebookCallback() {
  const navigate = useNavigate();

  useEffect(() => {
    const hash = window.location.hash; // "#access_token=xxx..."
    const params = new URLSearchParams(hash.replace("#", ""));

    const accessToken = params.get("access_token");

    if (!accessToken) {
      alert("Facebook login failed!");
      navigate("/login");
      return;
    }

    // Lấy info user từ Facebook API
    fetch(`https://graph.facebook.com/me?fields=name,email,picture&access_token=${accessToken}`)
      .then((res) => res.json())
      .then(async (fbUser) => {
        const response = await fetch("http://localhost:5000/api/auth/facebook-login", {
          method: "POST",
          headers: { "Content-Type": "application/json" },
          body: JSON.stringify({
            name: fbUser.name,
            email: fbUser.email,
            facebookId: fbUser.id,
            picture: fbUser.picture?.data?.url || "",
          }),
        });

        const data = await response.json();

        if (data.success) {
          localStorage.setItem("userInfo", JSON.stringify(data.user));
          navigate("/");
        } else {
          alert("Facebook login backend error!");
          navigate("/login");
        }
      });
  }, [navigate]);

  return <p>Đang đăng nhập...</p>;
}
